const input = items[0]?.json || {};
const missing = [];
function env(name, fallback = '') {
  const value = $env[name] || fallback;
  if (!value) missing.push(name);
  return value;
}
const config = {
  plataformaImportUrl: env('PLATAFORMA_COMERCIAL_IMPORT_URL', 'https://plataf-op-hml.vercel.app/api/comercial/hotmart/import'),
  plataformaTenantId: env('PLATAFORMA_TENANT_ID'),
  n8nIngestToken: env('N8N_INGEST_TOKEN')
};
if (missing.length) throw new Error('Variaveis ausentes no n8n: ' + missing.join(', '));
return [{ json: { ...input, config } }];

function get(obj, path) {
  return path.split('.').reduce((acc, key) => {
    if (!acc || typeof acc !== 'object') return undefined;
    return acc[key];
  }, obj);
}
function first(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return null;
}
function text(...values) {
  const value = first(...values);
  return value === null ? null : String(value).trim();
}
function number(...values) {
  const value = first(...values);
  if (value === null) return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;
  if (typeof value === 'object') return number(value.value, value.amount, value.total, value.price);
  const normalized = String(value).replace(/\s/g, '').replace(/R\$/gi, '').replace(/\./g, '').replace(',', '.');
  const parsed = Number(normalized);
  return Number.isFinite(parsed) ? parsed : null;
}
function integer(...values) {
  const value = number(...values);
  return value ? Math.max(1, Math.round(value)) : 1;
}
function date(...values) {
  const value = first(...values);
  if (value === null) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
}
function array(...values) {
  for (const value of values) {
    if (Array.isArray(value)) return value;
  }
  return [];
}
function commissionValue(item, purchase, data) {
  const direct = number(item.net_amount, item.valor_liquido, item.producer_net_amount, get(item, 'commission.value'), get(item, 'commission.amount'), get(data, 'commission.value'), get(data, 'commission.amount'), get(purchase, 'commission.value'));
  if (direct !== null) return direct;
  const commissions = array(item.commissions, data.commissions, purchase.commissions);
  const producer = commissions.find((commission) => {
    const source = String(commission.source || commission.role || commission.type || commission.name || '').toUpperCase();
    return source.includes('PRODUCER') || source.includes('PRODUTOR') || source.includes('SELLER');
  });
  return producer ? number(producer.value, producer.amount, producer.commission) : null;
}
function firstReceivableDate(item, purchase, data) {
  const receivables = array(item.receivables, item.installments, data.receivables, purchase.receivables);
  for (const receivable of receivables) {
    const found = date(receivable.expected_payment_date, receivable.payment_date, receivable.release_date, receivable.due_date, receivable.date);
    if (found) return found;
  }
  return null;
}
function normalizeHotmartRow(item, eventName) {
  const data = item.data || item;
  const purchase = data.purchase || item.purchase || item;
  const buyer = data.buyer || purchase.buyer || item.buyer || {};
  const product = data.product || purchase.product || item.product || {};
  const payment = data.payment || purchase.payment || item.payment || {};
  const price = purchase.price || data.price || item.price || {};
  const transactionId = text(purchase.transaction, get(purchase, 'transaction.code'), data.transaction, item.transaction, item.transaction_id, item.purchase_transaction, item.id);
  return {
    event_id: text(item.event_id, item.id, get(item, 'event.id'), eventName && transactionId ? `${eventName}-${transactionId}` : null),
    transaction_id: transactionId,
    event: text(item.event, item.event_name, item.type, eventName),
    product_id: text(product.id, product.ucode, item.product_id, item.hotmart_product_id),
    product_name: text(product.name, product.title, item.product_name, item.produto_nome),
    buyer_email: text(buyer.email, item.buyer_email, item.email)?.toLowerCase() || null,
    buyer_name: text(buyer.name, buyer.full_name, item.buyer_name, item.name),
    buyer_phone: text(buyer.phone, buyer.phone_number, item.buyer_phone, item.telefone),
    status: text(purchase.status, data.status, item.purchase_status, item.status, item.event) || 'unknown',
    payment_type: text(payment.type, payment.method, purchase.payment_type, item.payment_type),
    installments: integer(payment.installments_number, payment.installments, purchase.installments_number, item.installments, item.parcelas),
    currency: text(price.currency_code, price.currency, item.currency, item.moeda) || 'BRL',
    gross_amount: number(price.value, purchase.price?.value, purchase.full_price?.value, data.price?.value, item.gross_amount, item.valor_bruto, item.price),
    net_amount: commissionValue(item, purchase, data),
    fees: number(data.fees?.value, purchase.fees?.value, item.fees, item.taxas),
    purchase_date: date(purchase.order_date, purchase.purchase_date, item.purchase_date, item.data_compra, data.creation_date),
    approved_date: date(purchase.approved_date, item.approved_date, item.data_aprovacao),
    refund_date: date(purchase.refund_date, item.refund_date, item.data_reembolso),
    chargeback_date: date(purchase.chargeback_date, item.chargeback_date, item.data_chargeback),
    expected_payment_date: date(firstReceivableDate(item, purchase, data), data.receivable?.expected_payment_date, data.payment?.expected_payment_date, item.expected_payment_date, item.data_prevista),
    source_sck: text(data.tracking?.source_sck, purchase.tracking?.source_sck, item.tracking?.source_sck, item.source_sck, item.sck),
    raw_payload: item
  };
}

const input = items[0]?.json || {};
const config = input.config || {};
const body = input.body || input;
const row = normalizeHotmartRow(body, text(body.event, body.event_name, body.type, 'hotmart_webhook'));
if (!row.transaction_id) {
  return [{ json: { config, rows: [], skipped: true, reason: 'Evento Hotmart ignorado: transaction_id ausente.', raw_payload: body } }];
}
return [{ json: { config, tenant_id: config.plataformaTenantId, rows: [row], count: 1, reason: null } }];
